    {
      "path": "test-website/styles.css",
      "description": "Update CSS with theme colors and responsive design",
      "type": "edit",
      "content": ":root {
    --primary-color: #3b82f6;
    --secondary-color: #1e40af;
    --background-color: #0f172a;
    --text-color: #f8fafc;
    --font-main: 'Inter', system-ui, sans-serif;
}

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-main);
    color: var(--text-color);
    background-color: var(--background-color);
    line-height: 1.5;
    min-height: 100vh;
}

#root {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
}

#main-nav {
    padding: 1rem 2rem;
    background: var(--primary-color);
    border-bottom: 1px solid var(--secondary-color);
}

#main-nav ul {
    list-style: none;
    display: flex;
    gap: 1.5rem;
    max-width: 1200px;
    margin: 0 auto;
}

#main-nav a {
    text-decoration: none;
    color: var(--text-color);
    font-weight: 500;
    transition: color 0.3s ease;
}

#main-nav a:hover {
    color: var(--secondary-color);
}

.hero, .contact-section {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 4rem 2rem;
    max-width: 1200px;
    margin: 0 auto;
    text-align: center;
}

.hero h1, .contact-section h1 {
    font-size: 3rem;
    margin-bottom: 1rem;
    color: var(--primary-color);
}

.hero p, .contact-section p {
    color: var(--text-color);
    margin-bottom: 2rem;
}

.test-message, .security-message {
    margin-top: 2rem;
    padding: 1rem;
    background: rgba(59, 130, 246, 0.1);
    border: 1px solid var(--primary-color);
    border-radius: 4px;
}

.test-message p, .security-message p {
    color: var(--primary-color);
    font-weight: 500;
}

.contact-section {
    text-align: left;
}

.contact-section h1 {
    text-align: center;
    color: var(--text-color);
}

form {
    width: 100%;
    max-width: 500px;
    margin: 0 auto;
}

.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.5rem;
    color: var(--primary-color);
    font-weight: 500;
}

.form-group input {
    width: 100%;
    padding: 0.75rem;
    background: var(--background-color);
    border: 1px solid var(--primary-color);
    color: var(--text-color);
    border-radius: 4px;
    transition: border-color 0.3s ease;
}

.form-group input:focus {
    outline: none;
    border-color: var(--secondary-color);
}

button {
    width: 100%;
    padding: 0.75rem;
    background: var(--primary-color);
    color: var(--text-color);
    border: none;
    border-radius: 4px;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.3s ease;
}

button:hover {
    background: var(--secondary-color);
}

footer {
    padding: 2rem;
    text-align: center;
    background: var(--primary-color);
    border-top: 1px solid var(--secondary-color);
}

footer p {
    color: var(--text-color);
}

@media (max-width: 768px) {
    .hero h1, .contact-section h1 {
        font-size: 2rem;
    }

    #main-nav ul {
        flex-direction: column;
        gap: 0.5rem;
        text-align: center;
    }
}"
  },
  {
    "path": "test-website/script.js",
      "description": "Create new script.js with form handling",
      "type": "edit",
      "content": "document.addEventListener('DOMContentLoaded', function() {
    const form = document.getElementById('contact-form');
    if (form) {
        form.addEventListener('submit', function(e) {
            e.preventDefault();

            const formData = new FormData(form);
            const data = Object.fromEntries(formData);

            console.log('Form data:', data);

            const successMessage = document.createElement('div');
            successMessage.className = 'success-message';
            successMessage.textContent = 'Form submitted successfully!';
            successMessage.style.cssText = `
                background: #10b981;
                color: white;
                padding: 1rem;
                border-radius: 4px;
                margin-top: 1rem;
                text-align: center;
            `;

            form.parentNode.insertBefore(successMessage, form.nextSibling);

            setTimeout(() => {
                successMessage.remove();
            }, 3000);

            form.reset();
        });
    }
});"
  }
]}

